import React, { useEffect, useState } from 'react';
import { HashRouter as Router, Routes, Route, useLocation, Navigate } from 'react-router-dom';
import { Feed } from './components/Section/Feed';
import { Nav } from './components/Package/Nav';
import { ChatWindow } from './components/Section/ChatWindow';
import { MessagesList } from './components/Section/MessagesList';
import { Profile } from './components/Page/Profile';
import { Login } from './components/Page/Login';
import { Activity } from './components/Page/Activity';
import { LiveCall } from './components/Page/LiveCall';
import { PostDetail } from './components/Page/PostDetail';
import { theme } from './Theme';
import { ThemeProvider } from './ThemeContext';
import { AnimatePresence, motion } from 'framer-motion';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { Loader } from './components/Core/Loader';
import { api, supabase } from './services/supabaseClient';
import { DS } from './Theme';

// --- Auth Guard ---
const RequireAuth = ({ children }: { children?: React.ReactNode }) => {
    const { user, loading } = useAuth();

    if (loading) {
        return <Loader fullscreen label="AUTHENTICATING" />;
    }

    if (!user) {
        return <Navigate to="/login" replace />;
    }

    return <>{children}</>;
};

const AnimatedRoutes = () => {
  const location = useLocation();

  return (
    <AnimatePresence mode="wait">
      {/* FIX: The Routes component does not accept a 'key' prop, which is needed by AnimatePresence.
          Wrapping Routes in a motion.div with the key resolves the TypeScript error and
          allows framer-motion to correctly animate route transitions. */}
      <motion.div key={location.pathname}>
        <Routes location={location}>
          <Route path="/login" element={<Login />} />

          {/* Protected Routes */}
          <Route path="/" element={<RequireAuth><Feed /></RequireAuth>} />
          <Route path="/profile/:userId" element={<RequireAuth><Profile /></RequireAuth>} />
          <Route path="/post/:postId" element={<RequireAuth><PostDetail /></RequireAuth>} />
          <Route path="/messages" element={<RequireAuth><MessagesList /></RequireAuth>} />
          <Route path="/messages/:friendId" element={<RequireAuth><ChatWindow /></RequireAuth>} />
          <Route path="/call/:friendId" element={<RequireAuth><LiveCall /></RequireAuth>} />
          <Route path="/activity" element={<RequireAuth><Activity /></RequireAuth>} />
        </Routes>
      </motion.div>
    </AnimatePresence>
  );
};

const NotificationContainer = () => {
    const { user } = useAuth();
    const [toast, setToast] = useState<{ message: string, visible: boolean } | null>(null);

    useEffect(() => {
        if(!user) return;
        const channel = supabase.channel('global_notif_listener')
            .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'notifications', filter: `user_id=eq.${user.id}` }, payload => {
                const type = payload.new.type;
                let msg = "New notification";
                if(type === 'like') msg = "Someone liked your moment";
                if(type === 'comment') msg = "New comment on your moment";
                if(type === 'follow') msg = "You have a new follower";

                setToast({ message: msg, visible: true });
                setTimeout(() => setToast(null), 3000);
            })
            .subscribe();

        return () => { supabase.removeChannel(channel); };
    }, [user]);

    return (
        <AnimatePresence>
            {toast && (
                <motion.div 
                    initial={{ opacity: 0, y: -20, x: '-50%' }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -20 }}
                    style={{ 
                        position: 'fixed', top: '24px', left: '50%', transform: 'translateX(-50%)', 
                        background: DS.Color.Accent.Surface, color: 'white', padding: '12px 24px', 
                        borderRadius: DS.Radius.Full, boxShadow: DS.Effect.Shadow.Soft, zIndex: 9999,
                        fontWeight: 600, fontSize: '14px'
                    }}
                >
                    {toast.message}
                </motion.div>
            )}
        </AnimatePresence>
    )
}

const AppLayout: React.FC = () => {
  const { user } = useAuth();

  return (
    <div style={{ 
      fontFamily: theme.fonts.body, 
      color: theme.colors.text1, 
      background: theme.colors.surface1, 
      minHeight: '100%', 
      width: '100%',
      position: 'relative',
      overflowX: 'hidden',
      transition: 'background-color 0.6s cubic-bezier(0.22, 1, 0.36, 1), color 0.6s cubic-bezier(0.22, 1, 0.36, 1)'
    }}>
      <NotificationContainer />
      <AnimatedRoutes />
      {/* Only show Nav if logged in and not on login page */}
      {user && <Nav />}
    </div>
  );
};

const App: React.FC = () => {
  return (
    <ThemeProvider>
      <AuthProvider>
        <Router>
          <AppLayout />
        </Router>
      </AuthProvider>
    </ThemeProvider>
  );
};

export default App;

import React, { useEffect, useState, useRef } from 'react';
import { PostCard } from '../Package/PostCard';
import { api, supabase } from '../../services/supabaseClient';
import { Post, CurrentUser } from '../../types';
import { CircleNotch, Image as ImageIcon, PaperPlaneRight, Sun, Moon, Bell } from '@phosphor-icons/react';
import { Avatar } from '../Core/Avatar';
import { Button } from '../Core/Button';
import { Loader } from '../Core/Loader';
import { Link, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { DS } from '../../Theme';
import { useTheme } from '../../ThemeContext';
import { Confetti } from '../Core/Confetti';

export const Feed: React.FC = () => {
  const { mode, toggleTheme } = useTheme();
  const navigate = useNavigate();
  const [posts, setPosts] = useState<Post[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentUser, setCurrentUser] = useState<CurrentUser | null>(null);
  const [unreadCount, setUnreadCount] = useState(0);

  // Input State
  const [caption, setCaption] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [isPosting, setIsPosting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Easter Egg State
  const [showConfetti, setShowConfetti] = useState(false);
  const [showEasterEgg, setShowEasterEgg] = useState(false);
  const pressTimer = useRef<number | null>(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        const [user, feedData] = await Promise.all([
          api.getCurrentUser(),
          api.getFeed()
        ]);
        setCurrentUser(user);
        setPosts(feedData);

        // Initial Notification Check
        if (user) {
             const notifs = await api.getNotifications();
             setUnreadCount(notifs.filter(n => !n.is_read).length);
        }

      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    loadData();

    // Realtime Notification Subscription
    let channel: any;
    api.getCurrentUser().then(user => {
       if(!user) return;
       channel = supabase.channel('public:notifications')
       .on(
          'postgres_changes',
          { event: 'INSERT', schema: 'public', table: 'notifications', filter: `user_id=eq.${user.id}` },
          (payload) => {
              setUnreadCount(prev => prev + 1);
          }
       )
       .subscribe();
    });

    return () => {
        if(channel) supabase.removeChannel(channel);
        if (pressTimer.current) clearTimeout(pressTimer.current);
    };

  }, []);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const f = e.target.files[0];
      setFile(f);
      setPreview(URL.createObjectURL(f));
    }
  };

  const handlePost = async () => {
    if (!currentUser) return;
    if (!caption && !file) return;

    setIsPosting(true);
    try {
      let imageUrl = '';
      if (file) {
         imageUrl = await api.uploadFile(file);
      } else {
         imageUrl = `https://picsum.photos/seed/${Date.now()}/600/600`; 
      }

      await api.createPost(imageUrl, caption, currentUser.id);

      const newPost: Post = {
        id: `temp_${Date.now()}`,
        user_id: currentUser.id,
        image_url: preview || imageUrl,
        caption: caption,
        created_at: new Date().toISOString(),
        profiles: currentUser,
        likes_count: 0,
        has_liked: false,
        comments_count: 0
      };
      setPosts(prev => [newPost, ...prev]);
      setCaption('');
      setFile(null);
      setPreview(null);
    } catch (e) {
      console.error(e);
    } finally {
      setIsPosting(false);
    }
  };

  // Easter Egg Handlers
  const handleLogoStart = (e: React.SyntheticEvent) => {
    pressTimer.current = window.setTimeout(() => {
        triggerEasterEgg();
    }, 300);
  };

  const handleLogoEnd = () => {
    if (pressTimer.current) {
        clearTimeout(pressTimer.current);
        pressTimer.current = null;
    }
  };

  const triggerEasterEgg = () => {
    if (navigator.vibrate) navigator.vibrate([50, 50, 50]);
    setShowConfetti(true);
    setShowEasterEgg(true);
  };

  if (loading) {
    return <Loader fullscreen label="INITIALIZING" />;
  }

  return (
    <div style={{ 
      background: DS.Color.Base.Surface[1], 
      minHeight: '100%', 
      width: '100%',
      display: 'flex', 
      justifyContent: 'center' 
    }}>
      <div style={{ width: '100%', maxWidth: '500px', paddingBottom: '100px' }}>

        {/* Header */}
        <header style={{ 
          padding: '24px', 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center',
          position: 'sticky',
          top: 0,
          zIndex: 50,
          background: DS.Color.Base.Surface[1], // Opaque for scroll
        }}>
           <div
             onMouseDown={handleLogoStart}
             onMouseUp={handleLogoEnd}
             onMouseLeave={handleLogoEnd}
             onTouchStart={handleLogoStart}
             onTouchEnd={handleLogoEnd}
             onContextMenu={(e) => e.preventDefault()}
             style={{ cursor: 'pointer', userSelect: 'none', WebkitUserSelect: 'none', touchAction: 'none' }}
           >
             <h1 style={{ fontSize: '32px', color: DS.Color.Base.Content[1], ...DS.Type.Expressive.Display, pointerEvents: 'none' }}>
               OURS<span style={{ color: DS.Color.Accent.Surface }}>.</span>
             </h1>
           </div>

           <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
             <Button variant="ghost" size="icon" onClick={() => navigate('/activity')} style={{ position: 'relative' }}>
                <Bell size={24} />
                {unreadCount > 0 && (
                    <span style={{ 
                        position: 'absolute', top: 6, right: 6, 
                        width: '8px', height: '8px', 
                        background: DS.Color.Accent.Surface, 
                        borderRadius: '50%',
                        border: `1px solid ${DS.Color.Base.Surface[1]}`
                    }} />
                )}
             </Button>
             <Button variant="ghost" size="icon" onClick={toggleTheme}>
               {mode === 'dark' ? <Moon size={20} /> : <Sun size={20} />}
             </Button>
             <Link to={`/profile/${currentUser?.id}`}>
                <Avatar src={currentUser?.avatar_url || ''} alt="me" size="sm" />
             </Link>
           </div>
        </header>

        {/* Input Area */}
        <div style={{ padding: '0 16px 32px 16px' }}>
          <motion.div 
            layout
            style={{ 
              background: DS.Color.Base.Surface[2],
              borderRadius: DS.Radius.Full, // Peel/Pill shape
              padding: '8px 8px 8px 16px', 
              display: 'flex',
              alignItems: 'center',
              gap: '12px',
              border: `1px solid ${DS.Color.Base.Border}`
            }}
          >
            <input
                value={caption}
                onChange={(e) => setCaption(e.target.value)}
                placeholder="Share a moment..."
                style={{ 
                  flex: 1, 
                  background: 'transparent', 
                  border: 'none', 
                  outline: 'none', 
                  color: DS.Color.Base.Content[1], 
                  ...DS.Type.Readable.Body
                }}
            />

            <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                <input 
                  type="file" 
                  accept="image/*" 
                  ref={fileInputRef} 
                  style={{ display: 'none' }} 
                  onChange={handleFileSelect}
                />

                <Button variant="ghost" size="icon" onClick={() => fileInputRef.current?.click()}>
                  <ImageIcon size={20} weight={preview ? 'fill' : 'regular'} color={preview ? DS.Color.Accent.Surface : undefined} />
                </Button>

                <Button 
                  variant={caption || file ? "primary" : "secondary"} 
                  size="icon"
                  onClick={handlePost}
                  disabled={(!caption && !file) || isPosting}
                >
                  {isPosting ? <CircleNotch className="animate-spin" /> : <PaperPlaneRight size={18} weight="fill" />}
                </Button>
            </div>
          </motion.div>

          <AnimatePresence>
             {preview && (
                <motion.div 
                  initial={{ opacity: 0, height: 0, marginTop: 0 }}
                  animate={{ opacity: 1, height: 'auto', marginTop: 8 }}
                  exit={{ opacity: 0, height: 0, marginTop: 0 }}
                  style={{ overflow: 'hidden', borderRadius: DS.Radius.M }}
                >
                   <div style={{ position: 'relative' }}>
                     <img src={preview} alt="prev" style={{ width: '100%', height: '200px', objectFit: 'cover', borderRadius: DS.Radius.M }} />
                     <button onClick={() => { setPreview(null); setFile(null); }} style={{ position: 'absolute', top: 8, right: 8, background: 'rgba(0,0,0,0.5)', color: 'white', border: 'none', borderRadius: '50%', width: 24, height: 24 }}>✕</button>
                   </div>
                </motion.div>
             )}
          </AnimatePresence>
        </div>

        {/* Feed Stream */}
        <div style={{ padding: '0 16px' }}>
          {posts.map((post) => (
            <PostCard key={post.id} post={post} currentUser={currentUser!} />
          ))}
        </div>

        <div style={{ height: '100px', display: 'flex', justifyContent: 'center', alignItems: 'center', opacity: 0.3 }}>
           <div style={{ width: '4px', height: '4px', borderRadius: '50%', background: DS.Color.Base.Content[3] }}></div>
        </div>

        {/* Easter Egg Overlay */}
        <AnimatePresence>
            {showEasterEgg && (
                <>
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={() => { setShowEasterEgg(false); setShowConfetti(false); }}
                        style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.8)', zIndex: 9998, backdropFilter: 'blur(4px)' }}
                    />
                    <motion.div
                        initial={{ opacity: 0, scale: 0.8, y: '-50%', x: '-50%' }}
                        animate={{ opacity: 1, scale: 1, y: '-50%', x: '-50%' }}
                        exit={{ opacity: 0, scale: 0.8, y: '-50%', x: '-50%' }}
                        style={{
                            position: 'fixed', top: '50%', left: '50%',
                            zIndex: 9999,
                            background: DS.Color.Base.Surface[2],
                            padding: '32px',
                            borderRadius: DS.Radius.L,
                            border: `1px solid ${DS.Color.Accent.Surface}`,
                            textAlign: 'center',
                            width: '90%',
                            maxWidth: '400px',
                            boxShadow: `0 0 50px ${DS.Color.Accent.Surface}40`
                        }}
                    >
                        <h2 style={{ 
                            fontSize: '20px', 
                            color: DS.Color.Base.Content[1], 
                            marginBottom: '24px', 
                            lineHeight: 1.5,
                            fontFamily: DS.Type.Readable.Body.fontFamily 
                        }}>
                            যে বাল ছিড়তে পারবা না, সে বাল টানতে যাইও না
                        </h2>
                        <Button 
                            variant="primary" 
                            onClick={() => { setShowEasterEgg(false); setShowConfetti(false); }}
                            style={{ width: '100%' }}
                        >
                            Okay
                        </Button>
                    </motion.div>
                </>
            )}
        </AnimatePresence>
        {showConfetti && <Confetti />}

      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { api, supabase } from '../../services/supabaseClient';
import { Notification } from '../../types';
import { Avatar } from '../Core/Avatar';
import { motion, AnimatePresence } from 'framer-motion';
import { DS, theme, commonStyles } from '../../Theme';
import { Bell, Heart, ChatCircle, UserPlus, CaretLeft } from '@phosphor-icons/react';
import { formatDistanceToNow } from 'date-fns';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { Loader } from '../Core/Loader';

export const Activity: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchNotifications = async () => {
     try {
         const data = await api.getNotifications();
         setNotifications(data);
     } catch (e) {
         console.error("Failed to load notifications", e);
     }
  };

  useEffect(() => {
    const load = async () => {
        await fetchNotifications();
        setLoading(false);
    };
    load();

    // Real-time Subscription
    let channel: any;
    if (user) {
        channel = supabase.channel('activity_feed_realtime')
            .on(
                'postgres_changes',
                { event: 'INSERT', schema: 'public', table: 'notifications', filter: `user_id=eq.${user.id}` },
                async () => {
                    await fetchNotifications(); // Refresh on new item
                }
            )
            .subscribe();
    }

    return () => {
        if (channel) supabase.removeChannel(channel);
    };
  }, [user]);

  const handleInteraction = async (n: Notification) => {
      // Optimistic update
      if (!n.is_read) {
          setNotifications(prev => prev.map(item => item.id === n.id ? { ...item, is_read: true } : item));
          await api.markNotificationRead(n.id);
      }

      if (n.type === 'follow') {
           navigate(`/profile/${n.sender_profile?.id}`);
      } else {
           navigate(`/post/${n.reference_id}`);
      }
  };

  const getIcon = (type: string) => {
      switch(type) {
          case 'like': return <Heart weight="fill" color={DS.Color.Status.Error} size={12} />;
          case 'comment': return <ChatCircle weight="fill" color={DS.Color.Accent.Surface} size={12} />;
          case 'follow': return <UserPlus weight="fill" color="#22c55e" size={12} />;
          default: return <Bell weight="fill" color={DS.Color.Base.Content[3]} size={12} />;
      }
  };

  const getIconBg = (type: string) => {
      switch(type) {
          case 'like': return 'rgba(255, 51, 51, 0.1)';
          case 'comment': return 'rgba(255, 79, 31, 0.1)';
          case 'follow': return 'rgba(34, 197, 94, 0.1)';
          default: return DS.Color.Base.Surface[2];
      }
  };

  if (loading) {
     return <Loader fullscreen label="ACTIVITY" />;
  }

  return (
    <div style={commonStyles.pageContainer}>
        <div style={{ width: '100%', maxWidth: theme.layout.maxWidth, minHeight: '100%', paddingBottom: '100px' }}>

            {/* Header */}
            <div style={{ 
                padding: '24px 24px 16px 24px', 
                position: 'sticky', top: 0, zIndex: 50,
                background: `linear-gradient(to bottom, ${DS.Color.Base.Surface[1]} 80%, transparent 100%)`,
                backdropFilter: 'blur(12px)',
                WebkitBackdropFilter: 'blur(12px)',
                display: 'flex', alignItems: 'center', gap: '16px'
            }}>
                <button 
                    onClick={() => navigate(-1)}
                    style={{ background: 'none', border: 'none', color: theme.colors.text1, cursor: 'pointer', display: 'flex' }}
                >
                    <CaretLeft size={24} />
                </button>
                <h1 style={{ ...DS.Type.Expressive.Display, fontSize: '32px', color: theme.colors.text1, margin: 0 }}>
                    Activity<span style={{ color: theme.colors.accent }}>.</span>
                </h1>
            </div>

            {/* List */}
            <div style={{ padding: '0 16px', display: 'flex', flexDirection: 'column', gap: '0' }}>
                <AnimatePresence>
                {notifications.length === 0 ? (
                    <motion.div 
                        initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
                        style={{ padding: '64px 0', textAlign: 'center', opacity: 0.5, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '16px' }}
                    >
                        <div style={{ 
                            width: '64px', height: '64px', borderRadius: '50%', 
                            background: DS.Color.Base.Surface[2], display: 'flex', alignItems: 'center', justifyContent: 'center' 
                        }}>
                            <Bell size={24} weight="duotone" color={theme.colors.text3} />
                        </div>
                        <p style={{ ...DS.Type.Readable.Body, color: theme.colors.text3 }}>No recent activity.</p>
                    </motion.div>
                ) : (
                    notifications.map((n, i) => (
                        <NotificationItem 
                            key={n.id} 
                            notification={n} 
                            index={i} 
                            icon={getIcon(n.type)} 
                            iconBg={getIconBg(n.type)}
                            onClick={() => handleInteraction(n)}
                        />
                    ))
                )}
                </AnimatePresence>
            </div>

            <div style={{ height: '80px', display: 'flex', justifyContent: 'center', alignItems: 'center', opacity: 0.3 }}>
                 <div style={{ width: '4px', height: '4px', borderRadius: '50%', background: DS.Color.Base.Content[3] }}></div>
            </div>

        </div>
    </div>
  );
};

interface NotificationItemProps {
    notification: Notification;
    index: number;
    icon: React.ReactNode;
    iconBg: string;
    onClick: () => void;
}

const NotificationItem: React.FC<NotificationItemProps> = ({ notification, index, icon, iconBg, onClick }) => {
    let timeLabel = '';
    try {
        timeLabel = formatDistanceToNow(new Date(notification.created_at), { addSuffix: true })
            .replace('about ', '')
            .replace('less than a minute', 'just now');
    } catch (e) {}

    const isUnread = !notification.is_read;

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.05, ...DS.Motion.Spring.Gentle }}
            onClick={onClick}
            style={{
                display: 'flex',
                alignItems: 'center',
                gap: '16px',
                padding: '16px',
                borderRadius: DS.Radius.L,
                background: isUnread ? DS.Color.Base.Surface[2] : 'transparent',
                position: 'relative',
                cursor: 'pointer',
                marginBottom: '4px',
            }}
            whileHover={{ backgroundColor: DS.Color.Base.Surface[2], scale: 0.99 }}
            whileTap={{ scale: 0.98 }}
        >
             {/* Avatar with Badge */}
             <div style={{ position: 'relative', flexShrink: 0 }}>
                <Link to={`/profile/${notification.sender_profile?.id}`} onClick={(e) => e.stopPropagation()}>
                    <Avatar src={notification.sender_profile?.avatar_url || ''} alt="user" size="md" />
                </Link>
                <div style={{
                    position: 'absolute', bottom: -4, right: -4,
                    background: DS.Color.Base.Surface[1], // Border color match
                    borderRadius: '50%', padding: '2px', // Pseudo border
                }}>
                    <div style={{
                        width: '20px', height: '20px',
                        borderRadius: '50%',
                        background: iconBg, // Specific bg for type
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        backdropFilter: 'blur(4px)',
                        border: `1px solid ${DS.Color.Base.Surface[3]}`
                    }}>
                        {icon}
                    </div>
                </div>
             </div>

             {/* Text Content */}
             <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '2px' }}>
                 <p style={{ fontSize: '14px', lineHeight: '1.4', color: theme.colors.text1, margin: 0 }}>
                     <span style={{ fontWeight: 600 }}>{notification.sender_profile?.username || 'Someone'}</span>
                     <span style={{ color: theme.colors.text2, marginLeft: '4px' }}>
                         {notification.type === 'like' && 'liked your moment.'}
                         {notification.type === 'comment' && 'commented on your moment.'}
                         {notification.type === 'follow' && 'started following you.'}
                     </span>
                 </p>
                 <span style={{ fontSize: '12px', color: theme.colors.text3, fontWeight: 500 }}>{timeLabel}</span>
             </div>

             {/* Right Side Interaction */}
             {notification.type === 'follow' ? (
                 <button style={{
                     padding: '6px 14px',
                     borderRadius: DS.Radius.Full,
                     background: DS.Color.Base.Surface[3],
                     color: theme.colors.text1,
                     fontSize: '12px',
                     fontWeight: 600,
                     border: `1px solid ${DS.Color.Base.Border}`,
                     cursor: 'pointer',
                     whiteSpace: 'nowrap'
                 }}>
                     View
                 </button>
             ) : (
                <div style={{
                    width: '40px', height: '40px',
                    borderRadius: DS.Radius.M,
                    overflow: 'hidden',
                    flexShrink: 0,
                    background: DS.Color.Base.Surface[3],
                    border: `1px solid ${DS.Color.Base.Border}`
                }}>
                    <img 
                        src={notification.media_url || `https://picsum.photos/seed/${notification.reference_id}/100/100`} 
                        alt="ref" 
                        style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
                    />
                </div>
             )}

             {/* Unread Dot */}
             {isUnread && (
                 <div style={{ 
                     position: 'absolute', top: '16px', right: '16px',
                     width: '6px', height: '6px', borderRadius: '50%', background: DS.Color.Accent.Surface 
                 }} />
             )}
        </motion.div>
    );
};

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { DS } from '../../Theme';
import { api } from '../../services/supabaseClient';
import { useNavigate } from 'react-router-dom';
import { User, Key, SignIn, WarningCircle, IdentificationCard, PaperPlaneRight, ArrowLeft } from '@phosphor-icons/react';
import { Button } from '../Core/Button';
import { Input } from '../Core/Input';
import { useAuth } from '../../contexts/AuthContext';

type AuthView = 'login' | 'register' | 'reset';

export const Login: React.FC = () => {
  const navigate = useNavigate();
  const { refreshAuth } = useAuth();
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  // State: 'login' | 'register' | 'reset'
  const [view, setView] = useState<AuthView>('login');

  // Form State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');

  const handleSwitchView = (newView: AuthView) => {
    setView(newView);
    setError('');
    setSuccessMsg('');
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');
    setSuccessMsg('');

    try {
        if (view === 'register') {
            if (!fullName.trim()) throw new Error("Name is required");
            await api.signUpWithEmail(email, password, fullName);
            handleSwitchView('login');
            setSuccessMsg("Account created! Please log in.");
        } else if (view === 'reset') {
            if (!email.trim()) throw new Error("Email is required");
            await api.resetPassword(email);
            setSuccessMsg("Check your email for reset instructions.");
        } else {
            // Login (or Secret Guest)
            await api.signInWithPassword(email, password);
            await refreshAuth();
            navigate('/');
        }
    } catch (err: any) {
        console.error(err);
        setError(err.message || 'Authentication failed');
    } finally {
        setIsLoading(false);
    }
  };

  // UI Text Logic
  const getHeadline = () => {
    switch(view) {
        case 'register': return "Join the void.";
        case 'reset': return "Recover access.";
        default: return "Enter the void.";
    }
  };

  // Variants to handle overflow visibility for focus ring clipping
  // Adjusted to always keep overflow visible as requested
  const fieldContainerVariants = {
    hidden: { opacity: 0, height: 0, overflow: 'visible' },
    visible: { 
      opacity: 1, 
      height: 'auto', 
      overflow: 'visible'
    },
    exit: { opacity: 0, height: 0, overflow: 'visible' }
  };

  return (
    <div style={{ 
      minHeight: '100%', 
      width: '100%', 
      background: '#000000', 
      display: 'flex', 
      flexDirection: 'column', 
      alignItems: 'center', 
      justifyContent: 'center',
      color: '#FFFFFF'
    }}>

      {/* Floating Particles Background Effect */}
      <div style={{ position: 'absolute', inset: 0, overflow: 'hidden', pointerEvents: 'none' }}>
         {[...Array(20)].map((_, i) => (
            <motion.div
              key={i}
              initial={{ 
                x: Math.random() * window.innerWidth, 
                y: Math.random() * window.innerHeight,
                opacity: 0.1,
                scale: Math.random() * 0.5 + 0.5
              }}
              animate={{ 
                y: [null, Math.random() * window.innerHeight],
                opacity: [0.1, 0.3, 0.1]
              }}
              transition={{ duration: 10 + Math.random() * 20, repeat: Infinity, ease: "linear" }}
              style={{
                position: 'absolute',
                width: '4px',
                height: '4px',
                borderRadius: '50%',
                background: DS.Color.Accent.Surface
              }}
            />
         ))}
      </div>

      <div style={{ maxWidth: '360px', padding: '24px', width: '100%', textAlign: 'center', position: 'relative', zIndex: 10 }}>

        <motion.div
          key={view}
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.5, ease: [0.25, 0.1, 0.25, 1] }}
          style={{ marginBottom: '48px' }}
        >
          <h1 style={{ 
            fontSize: '80px', 
            letterSpacing: '-2px',
            lineHeight: 0.9,
            fontFamily: DS.Type.Expressive.Display.fontFamily
          }}>
            OURS<span style={{ color: DS.Color.Accent.Surface }}>.</span>
          </h1>
          <p style={{ 
            color: DS.Color.Base.Content[3], 
            fontSize: '16px', 
            marginTop: '16px',
            fontFamily: DS.Type.Expressive.Quote.fontFamily
          }}>
            {getHeadline()}
          </p>
        </motion.div>

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '16px', marginBottom: '24px' }}>

           <AnimatePresence mode="popLayout">
             {view === 'register' && (
               <motion.div
                 variants={fieldContainerVariants}
                 initial="hidden"
                 animate="visible"
                 exit="exit"
                 style={{ overflow: 'visible' }}
               >
                  <Input 
                    placeholder="Full Name" 
                    icon={<IdentificationCard size={20} />}
                    value={fullName}
                    onChange={e => setFullName(e.target.value)}
                    style={{ background: 'rgba(255,255,255,0.05)' }}
                    required={view === 'register'}
                  />
               </motion.div>
             )}
           </AnimatePresence>

           <Input 
              placeholder="Email / ID" 
              icon={<User size={20} />}
              value={email}
              onChange={e => setEmail(e.target.value)}
              style={{ background: 'rgba(255,255,255,0.05)' }}
              required
           />

           <AnimatePresence mode="popLayout">
             {view !== 'reset' && (
                <motion.div
                   variants={fieldContainerVariants}
                   initial="hidden"
                   animate="visible"
                   exit="exit"
                   style={{ overflow: 'visible' }}
                >
                    <Input 
                        type="password"
                        placeholder="Password" 
                        icon={<Key size={20} />}
                        value={password}
                        onChange={e => setPassword(e.target.value)}
                        style={{ background: 'rgba(255,255,255,0.05)', marginBottom: '8px' }}
                        required
                    />

                    {view === 'login' && (
                        <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: '8px' }}>
                            <button
                                type="button"
                                onClick={() => handleSwitchView('reset')}
                                style={{
                                    background: 'none', border: 'none', 
                                    color: DS.Color.Base.Content[3], 
                                    fontSize: '12px', cursor: 'pointer',
                                    padding: '4px'
                                }}
                            >
                                Forgot Password?
                            </button>
                        </div>
                    )}
                </motion.div>
             )}
           </AnimatePresence>

           {/* Feedback Messages */}
           <AnimatePresence>
            {error && (
                <motion.div 
                initial={{ opacity: 0, y: -10 }} 
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
                style={{ color: '#FFF', fontSize: '13px', background: 'rgba(220, 38, 38, 0.2)', padding: '12px', borderRadius: '8px', display: 'flex', alignItems: 'center', gap: '8px', textAlign: 'left', border: `1px solid ${DS.Color.Status.Error}` }}
                >
                <WarningCircle size={20} weight="fill" flexShrink={0} color={DS.Color.Status.Error} />
                {error}
                </motion.div>
            )}
            {successMsg && (
                <motion.div 
                initial={{ opacity: 0, y: -10 }} 
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
                style={{ color: '#FFF', fontSize: '13px', background: 'rgba(34, 197, 94, 0.1)', padding: '12px', borderRadius: '8px', display: 'flex', alignItems: 'center', gap: '8px', textAlign: 'left', border: `1px solid #22c55e` }}
                >
                <PaperPlaneRight size={20} weight="fill" flexShrink={0} color="#22c55e" />
                {successMsg}
                </motion.div>
            )}
           </AnimatePresence>

           <Button variant="primary" size="lg" type="submit" disabled={isLoading} style={{ width: '100%' }}>
              {isLoading ? 'Processing...' : (
                  <>
                     {view === 'reset' ? <PaperPlaneRight size={20} weight="fill" /> : <SignIn size={20} weight="fill" />}
                     {view === 'register' ? 'CREATE ACCOUNT' : view === 'reset' ? 'SEND INSTRUCTIONS' : 'LOG IN'}
                  </>
              )}
           </Button>
        </form>

        <div style={{ display: 'flex', alignItems: 'center', gap: '16px', margin: '24px 0', opacity: 0.5 }}>
           <div style={{ height: '1px', flex: 1, background: DS.Color.Base.Border }}></div>
           <span style={{ fontSize: '12px', color: DS.Color.Base.Content[3] }}>OR</span>
           <div style={{ height: '1px', flex: 1, background: DS.Color.Base.Border }}></div>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {view === 'reset' ? (
                 <button 
                 onClick={() => handleSwitchView('login')}
                 style={{ 
                   background: 'none', border: 'none', color: DS.Color.Base.Content[3], 
                   fontSize: '14px', cursor: 'pointer', textDecoration: 'none',
                   display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px',
                   marginTop: '8px', transition: 'color 0.2s'
                 }}
               >
                 <ArrowLeft size={16} /> Back to Log In
               </button>
            ) : (
                <button 
                onClick={() => handleSwitchView(view === 'login' ? 'register' : 'login')}
                style={{ 
                  background: 'none', border: 'none', color: DS.Color.Base.Content[3], 
                  fontSize: '14px', cursor: 'pointer', textDecoration: 'none',
                  marginTop: '8px', transition: 'color 0.2s'
                }}
              >
                {view === 'login' ? "Don't have an account? Sign Up" : "Already have an account? Log In"}
              </button>
            )}
        </div>

      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api } from '../../services/supabaseClient';
import { Post, CurrentUser } from '../../types';
import { PostCard } from '../Package/PostCard';
import { CaretLeft } from '@phosphor-icons/react';
import { DS } from '../../Theme';
import { commonStyles, theme } from '../../Theme';
import { Loader } from '../Core/Loader';

export const PostDetail: React.FC = () => {
  const { postId } = useParams<{ postId: string }>();
  const navigate = useNavigate();
  const [post, setPost] = useState<Post | null>(null);
  const [currentUser, setCurrentUser] = useState<CurrentUser | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadData = async () => {
      if (!postId) return;
      try {
        setLoading(true);
        const [user, postData] = await Promise.all([
          api.getCurrentUser(),
          api.getPost(postId)
        ]);
        setCurrentUser(user);
        setPost(postData);
      } catch (e) {
        console.error("Failed to load post", e);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, [postId]);

  const handleBack = () => {
     if (window.history.length > 2) {
         navigate(-1);
     } else {
         navigate('/', { replace: true });
     }
  };

  if (loading) {
    return <Loader fullscreen label="LOADING MOMENT" />;
  }

  if (!post || !currentUser) {
    return (
      <div style={{ ...commonStyles.flexCenter, height: '100%', width: '100%', flexDirection: 'column', background: theme.colors.surface1, color: theme.colors.text2 }}>
        <p>Moment not found.</p>
        <button onClick={() => navigate('/')} style={{ marginTop: '16px', color: theme.colors.accent, background: 'none', border: 'none', cursor: 'pointer' }}>Return Home</button>
      </div>
    );
  }

  return (
    <div style={{ 
      background: DS.Color.Base.Surface[1], 
      minHeight: '100%', 
      width: '100%',
      display: 'flex', 
      justifyContent: 'center' 
    }}>
      <div style={{ width: '100%', maxWidth: '500px', paddingBottom: '100px' }}>

        {/* Header */}
        <div style={{ 
          padding: '24px', 
          display: 'flex', 
          alignItems: 'center',
          gap: '16px',
          position: 'sticky',
          top: 0,
          zIndex: 50,
          background: DS.Color.Base.Surface[1],
        }}>
           <button 
             onClick={handleBack} 
             style={{ 
               background: 'none', 
               border: 'none', 
               color: DS.Color.Base.Content[1], 
               display: 'flex', 
               alignItems: 'center', 
               gap: '8px', 
               cursor: 'pointer',
               ...DS.Type.Readable.Label
             }}
           >
             <CaretLeft size={20} /> BACK
           </button>
           <h2 style={{ ...DS.Type.Expressive.Display, fontSize: '20px', color: DS.Color.Base.Content[1] }}>Moment</h2>
        </div>

        {/* Post Content */}
        <div style={{ padding: '0 16px' }}>
          <PostCard post={post} currentUser={currentUser} />
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { api, supabase, parseMessageContent } from '../../../services/supabaseClient';
import { Message, CurrentUser } from '../../../types';
import { motion } from 'framer-motion';
import { theme, commonStyles } from '../../../Theme';
import { Lightbox } from '../../Core/Lightbox';
import { ChatHeader, ChatInput, MessageBubble } from './ChatPrimitives';

interface DirectChatProps {
    friendId: string;
}

export const DirectChat: React.FC<DirectChatProps> = ({ friendId }) => {
    const navigate = useNavigate();
    const [messages, setMessages] = useState<Message[]>([]);
    const [currentUser, setCurrentUser] = useState<CurrentUser | null>(null);
    const [friendProfile, setFriendProfile] = useState<any>(null);
    const [lightboxSrc, setLightboxSrc] = useState<string | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        setTimeout(scrollToBottom, 100);
    }, [messages.length]);

    useEffect(() => {
        let ignore = false;
        let channel: any = null;

        const init = async () => {
            const user = await api.getCurrentUser();
            if (ignore) return;
            setCurrentUser(user);

            // Fetch Messages
            const msgs = await api.getMessages(friendId);
            if (ignore) return;
            setMessages(msgs);

            const friend = (await api.getAllProfiles()).find(p => p.id === friendId);
            if (ignore) return;
            setFriendProfile(friend);

            // Subscribe to DM updates
            channel = supabase.channel(`dm:${user.id}:${friendId}`)
               .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'messages' }, payload => {
                   const msg = parseMessageContent(payload.new);

                   // REALTIME: Only add messages from the OTHER user. Own messages are handled optimistically.
                   if (msg.sender_id === friendId && msg.receiver_id === user.id) {
                        setMessages(prev => {
                           // Prevent duplicates from any stray events
                           if (prev.find(m => m.id === msg.id)) return prev;
                           return [...prev, msg];
                        });
                   }
               })
               .subscribe();
        };

        init();
        return () => { 
            ignore = true; 
            if(channel) supabase.removeChannel(channel); 
        };
    }, [friendId]);

    const handleSend = async (content: string, type: 'text'|'image'|'audio' = 'text', mediaUrl?: string) => {
        if (!currentUser) return;

        // Optimistic UI Update with a unique temporary ID
        const tempId = `local_${Date.now()}`;
        const optimisticMsg: Message = {
            id: tempId,
            sender_id: currentUser.id,
            receiver_id: friendId,
            content,
            type,
            media_url: mediaUrl,
            created_at: new Date().toISOString()
        };
        setMessages(prev => [...prev, optimisticMsg]);

        try {
            const savedMessage = await api.sendMessage(currentUser.id, friendId, content, type, mediaUrl);
            // Replace the optimistic message with the real one from the server
            setMessages(prev => prev.map(m => m.id === tempId ? savedMessage : m));
        } catch (e) {
            console.error("Send failed", e);
            // On failure, remove the optimistic message to indicate it wasn't sent
            setMessages(prev => prev.filter(m => m.id !== tempId));
        }
    };

    const startCall = () => {
        if (!currentUser) return;
        // Navigate to the serverless PeerJS call component, using the friend's ID directly.
        navigate(`/call/${friendId}`);
    };

    return (
        <>
            <Lightbox isOpen={!!lightboxSrc} src={lightboxSrc || ''} onClose={() => setLightboxSrc(null)} />
            <motion.div 
              {...theme.motion.page}
              style={{ 
                display: 'flex', flexDirection: 'column', height: '100%', 
                background: theme.colors.surface1, width: '100%', maxWidth: theme.layout.maxWidth, margin: '0 auto', position: 'relative', overflow: 'hidden'
              }}
            >
                <ChatHeader title={friendProfile?.username || 'Chat'} onCall={startCall} />

                <div className="scrollbar-hide" style={{ flex: 1, overflowY: 'auto', padding: '0 24px 100px 24px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
                    {messages.length === 0 && (
                       <div style={{ height: '100%', ...commonStyles.flexCenter, flexDirection: 'column', opacity: 0.3, gap: '16px' }}>
                          <div style={{ width: '40px', height: '40px', borderRadius: '50%', border: `1px solid ${theme.colors.text3}` }}></div>
                          <p style={{ fontSize: '12px', letterSpacing: '2px' }}>Start a conversation</p>
                       </div>
                    )}

                    {messages.map((msg) => (
                        <MessageBubble 
                            key={msg.id} 
                            msg={msg} 
                            isMe={msg.sender_id === currentUser?.id} 
                            onImageClick={(url) => setLightboxSrc(url)}
                        />
                    ))}
                    <div ref={messagesEndRef} style={{ height: '1px' }} />
                </div>

                <ChatInput onSend={handleSend} />
            </motion.div>
        </>
    );
};

import React from 'react';
import { motion } from 'framer-motion';
import { DS } from '../../Theme';

interface LoaderProps {
  fullscreen?: boolean;
  size?: 'sm' | 'md' | 'lg';
  label?: string;
}

export const Loader: React.FC<LoaderProps> = ({ fullscreen = false, size = 'md', label }) => {
  const sizeMap = {
    sm: 24,
    md: 48,
    lg: 80
  };

  const px = sizeMap[size];
  const half = px / 2;

  const containerStyle: React.CSSProperties = {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    width: '100%',
    height: '100%',
    background: fullscreen ? DS.Color.Base.Surface[1] : 'transparent',
    perspective: '800px', // Exaggerated perspective for toon look
    gap: '32px',
    position: fullscreen ? 'fixed' : 'relative',
    top: 0,
    left: 0,
    zIndex: fullscreen ? 9999 : 'auto',
  };

  const faceStyle: React.CSSProperties = {
    position: 'absolute',
    width: px,
    height: px,
    background: DS.Color.Accent.Surface, // Solid Brand Color
    border: '3px solid #000000', // Strict Black Outline (Toon Ink)
    opacity: 1, // Solid, no transparency
    boxShadow: 'none', // Glowless
    backfaceVisibility: 'hidden', // Clean faces
  };

  return (
    <div style={containerStyle}>
       <motion.div
         style={{
             width: px,
             height: px,
             position: 'relative',
             transformStyle: 'preserve-3d',
         }}
         animate={{
             rotateX: [0, 360],
             rotateY: [0, 360],
         }}
         transition={{
             duration: 3,
             ease: "linear",
             repeat: Infinity
         }}
       >
          {/* Front */}
          <div style={{ ...faceStyle, transform: `translateZ(${half}px)` }} />

          {/* Back */}
          <div style={{ ...faceStyle, transform: `rotateY(180deg) translateZ(${half}px)` }} />

          {/* Right */}
          <div style={{ ...faceStyle, transform: `rotateY(90deg) translateZ(${half}px)` }} />

          {/* Left */}
          <div style={{ ...faceStyle, transform: `rotateY(-90deg) translateZ(${half}px)` }} />

          {/* Top */}
          <div style={{ ...faceStyle, transform: `rotateX(90deg) translateZ(${half}px)` }} />

          {/* Bottom */}
          <div style={{ ...faceStyle, transform: `rotateX(-90deg) translateZ(${half}px)` }} />

       </motion.div>

       {label && (
           <motion.span
             initial={{ opacity: 0, y: 10 }}
             animate={{ opacity: 1, y: 0 }}
             transition={{ duration: 0.5 }}
             style={{
                 ...DS.Type.Expressive.Display,
                 fontSize: '18px',
                 letterSpacing: '0.1em',
                 color: DS.Color.Base.Content[1],
                 textTransform: 'uppercase',
                 textShadow: 'none' // Clean, no effects
             }}
           >
               {label}
           </motion.span>
       )}
    </div>
  );
};
